1	package federation
2	
3	import (
4		"bytes"
5		"context"
6		"crypto/rand"
7		"crypto/tls"
8		"encoding/hex"
9		"encoding/json"
10		"errors"
11		"fmt"
12		"io"
13		"log"
14		"math/big"
15		"net/http"
16		"net/url"
17		"os"
18		"path/filepath"
19		"strings"
20		"sync"
21		"time"
22	)
23	
24	// DefaultHeartbeatInterval is the nominal heartbeat cadence (ADR-007: 30s).
25	const DefaultHeartbeatInterval = 30 * time.Second
26	
27	// DefaultHeartbeatJitterFraction is applied to the interval as ±jitter so
28	// independent spokes do not synchronize their beats against one hub.
29	const DefaultHeartbeatJitterFraction = 0.25
30	
31	// DefaultDeregisterTimeout caps the best-effort deregister request on shutdown.
32	const DefaultDeregisterTimeout = 2 * time.Second
33	
34	// spokeStateFileName is the on-disk name for spoke-side state, used to detect
35	// URL changes across restarts so the spoke can re-register with a new URL.
36	const spokeStateFileName = "spoke-state.json"
37	
38	// SpokeState is the per-spoke persistent state. It records the URL last
39	// advertised to the hub and the stable identity_fingerprint generated on
40	// first start, both so URL changes can be detected across restarts and so
41	// re-registration can prove identity to the hub.
42	type SpokeState struct {
43		NodeID              string `json:"node_id"`
44		IdentityFingerprint string `json:"identity_fingerprint"`
45		LastURL             string `json:"last_url,omitempty"`
46	}
47	
48	// DefaultSpokeStatePath returns ~/.local/share/ddx/spoke-state.json (XDG aware).
49	func DefaultSpokeStatePath() (string, error) {
50		if xdg := os.Getenv("XDG_DATA_HOME"); xdg != "" {
51			return filepath.Join(xdg, "ddx", spokeStateFileName), nil
52		}
53		home, err := os.UserHomeDir()
54		if err != nil {
55			return "", fmt.Errorf("federation: cannot determine home directory: %w", err)
56		}
57		return filepath.Join(home, ".local", "share", "ddx", spokeStateFileName), nil
58	}
59	
60	// LoadSpokeState reads spoke state from path. Missing file → zero value.
61	func LoadSpokeState(path string) (*SpokeState, error) {
62		data, err := os.ReadFile(path)
63		if errors.Is(err, os.ErrNotExist) {
64			return &SpokeState{}, nil
65		}
66		if err != nil {
67			return nil, fmt.Errorf("federation: read spoke state: %w", err)
68		}
69		var st SpokeState
70		if err := json.Unmarshal(data, &st); err != nil {
71			// Corrupt file — start fresh; the caller will overwrite.
72			return &SpokeState{}, nil
73		}
74		return &st, nil
75	}
76	
77	// SaveSpokeState writes spoke state to path atomically (tmpfile+rename).
78	func SaveSpokeState(path string, st *SpokeState) error {
79		if st == nil {
80			return fmt.Errorf("federation: nil spoke state")
81		}
82		if err := os.MkdirAll(filepath.Dir(path), dirMode); err != nil {
83			return fmt.Errorf("federation: mkdir: %w", err)
84		}
85		data, err := json.MarshalIndent(st, "", "  ")
86		if err != nil {
87			return err
88		}
89		tmp, err := os.CreateTemp(filepath.Dir(path), ".spoke-state-*.json.tmp")
90		if err != nil {
91			return err
92		}
93		tmpPath := tmp.Name()
94		if _, err := tmp.Write(data); err != nil {
95			_ = tmp.Close()
96			_ = os.Remove(tmpPath)
97			return err
98		}
99		if err := tmp.Close(); err != nil {
100			_ = os.Remove(tmpPath)
101			return err
102		}
103		if err := os.Chmod(tmpPath, fileMode); err != nil {
104			_ = os.Remove(tmpPath)
105			return err
106		}
107		return os.Rename(tmpPath, path)
108	}
109	
110	// generateIdentityFingerprint returns a random 16-byte hex string. The
111	// fingerprint is generated once per node and persisted in spoke-state so a
112	// re-registration of the same node_id from the same machine is recognized
113	// as such (rather than rejected as a duplicate-identity conflict).
114	func generateIdentityFingerprint() string {
115		var buf [16]byte
116		if _, err := rand.Read(buf[:]); err != nil {
117			// Fall back to a hostname-derived value; collisions here are
118			// uninteresting because the hub's duplicate-id rejection only fires
119			// on a *different* fingerprint claiming the same node_id.
120			host, _ := os.Hostname()
121			return "fp-" + host
122		}
123		return "fp-" + hex.EncodeToString(buf[:])
124	}
125	
126	// SpokeConfig configures a Spoke lifecycle agent. URL is the spoke's own
127	// publicly-reachable URL (advertised to the hub); HubURL is the hub base URL
128	// (e.g. "https://hub.example:7743").
129	type SpokeConfig struct {
130		NodeID               string
131		Name                 string
132		URL                  string
133		HubURL               string
134		DDxVersion           string
135		SchemaVersion        string
136		GraphQLSchemaVersion string
137		Capabilities         []string
138	
139		// HeartbeatInterval defaults to DefaultHeartbeatInterval. Pass a small
140		// value (e.g. 50ms) in tests.
141		HeartbeatInterval time.Duration
142		// HeartbeatJitterFraction is the ± jitter as a fraction of the interval
143		// (e.g. 0.25 for ±25%). Defaults to DefaultHeartbeatJitterFraction.
144		HeartbeatJitterFraction float64
145		// DeregisterTimeout caps the best-effort deregister on shutdown.
146		DeregisterTimeout time.Duration
147	
148		// StatePath is the disk path for spoke-state.json. Empty → DefaultSpokeStatePath.
149		StatePath string
150		// HTTPClient is used for hub requests. Nil → default client that accepts
151		// self-signed certs (matches the server's auto-generated cert).
152		HTTPClient *http.Client
153		// Logger is used for warn/info; nil → log.Printf.
154		Logger func(format string, args ...any)
155	}
156	
157	// Spoke is the spoke-side lifecycle agent: register on Start, jittered
158	// heartbeat in the background, deregister best-effort on Shutdown.
159	type Spoke struct {
160		cfg                 SpokeConfig
161		identityFingerprint string
162	
163		mu              sync.Mutex
164		statePath       string
165		registered      bool
166		stopped         chan struct{}
167		stopOnce        sync.Once
168		registeredCount int // test introspection
169		heartbeatCount  int // test introspection
170		urlChanged      bool
171		urlChangedFrom  string
172		hbErr           error
173		logf            func(format string, args ...any)
174	}
175	
176	// NewSpoke constructs a Spoke with defaults filled in. The spoke is not
177	// started until Start is called.
178	func NewSpoke(cfg SpokeConfig) (*Spoke, error) {
179		if strings.TrimSpace(cfg.NodeID) == "" {
180			return nil, fmt.Errorf("federation: spoke NodeID required")
181		}
182		if strings.TrimSpace(cfg.HubURL) == "" {
183			return nil, fmt.Errorf("federation: spoke HubURL required")
184		}
185		if strings.TrimSpace(cfg.URL) == "" {
186			return nil, fmt.Errorf("federation: spoke URL required")
187		}
188		if cfg.HeartbeatInterval <= 0 {
189			cfg.HeartbeatInterval = DefaultHeartbeatInterval
190		}
191		if cfg.HeartbeatJitterFraction < 0 {
192			cfg.HeartbeatJitterFraction = 0
193		}
194		if cfg.HeartbeatJitterFraction == 0 {
195			cfg.HeartbeatJitterFraction = DefaultHeartbeatJitterFraction
196		}
197		if cfg.DeregisterTimeout <= 0 {
198			cfg.DeregisterTimeout = DefaultDeregisterTimeout
199		}
200		if cfg.HTTPClient == nil {
201			// Self-signed certs are the default for ddx-server, so the spoke
202			// must skip cert verification by default. Operators wanting stricter
203			// validation can pass a custom HTTPClient.
204			cfg.HTTPClient = &http.Client{
205				Timeout: 10 * time.Second,
206				Transport: &http.Transport{
207					TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
208				},
209			}
210		}
211	
212		statePath := cfg.StatePath
213		if statePath == "" {
214			p, err := DefaultSpokeStatePath()
215			if err != nil {
216				return nil, err
217			}
218			statePath = p
219		}
220	
221		logf := cfg.Logger
222		if logf == nil {
223			logf = func(format string, args ...any) { log.Printf(format, args...) }
224		}
225	
226		st, err := LoadSpokeState(statePath)
227		if err != nil {
228			return nil, err
229		}
230	
231		// Detect URL change between restarts.
232		var urlChanged bool
233		var prevURL string
234		if st.NodeID == cfg.NodeID && st.LastURL != "" && st.LastURL != cfg.URL {
235			urlChanged = true
236			prevURL = st.LastURL
237		}
238	
239		// Reuse fingerprint if it's for the same node_id; otherwise generate one.
240		fp := st.IdentityFingerprint
241		if fp == "" || st.NodeID != cfg.NodeID {
242			fp = generateIdentityFingerprint()
243		}
244	
245		s := &Spoke{
246			cfg:                 cfg,
247			identityFingerprint: fp,
248			statePath:           statePath,
249			stopped:             make(chan struct{}),
250			urlChanged:          urlChanged,
251			urlChangedFrom:      prevURL,
252			logf:                logf,
253		}
254		return s, nil
255	}
256	
257	// IdentityFingerprint returns the stable identity fingerprint persisted for
258	// this spoke. Useful for tests and operator diagnostics.
259	func (s *Spoke) IdentityFingerprint() string { return s.identityFingerprint }
260	
261	// URLChanged reports whether the spoke detected a URL change versus the
262	// last-known persisted state at startup time.
263	func (s *Spoke) URLChanged() bool { return s.urlChanged }
264	
265	// PreviousURL returns the URL recorded in spoke-state on disk before this
266	// start (empty if none). Distinct from URLChanged so callers can log either.
267	func (s *Spoke) PreviousURL() string { return s.urlChangedFrom }
268	
269	// HeartbeatCount returns the number of heartbeats sent (test introspection).
270	func (s *Spoke) HeartbeatCount() int {
271		s.mu.Lock()
272		defer s.mu.Unlock()
273		return s.heartbeatCount
274	}
275	
276	// RegisteredCount returns the number of register calls made (test introspection).
277	func (s *Spoke) RegisteredCount() int {
278		s.mu.Lock()
279		defer s.mu.Unlock()
280		return s.registeredCount
281	}
282	
283	// LastHeartbeatError returns the most recent heartbeat error or nil.
284	func (s *Spoke) LastHeartbeatError() error {
285		s.mu.Lock()
286		defer s.mu.Unlock()
287		return s.hbErr
288	}
289	
290	// Start performs the initial register-on-start and launches the jittered
291	// heartbeat goroutine. It returns the register error (if any); a successful
292	// Start means the hub accepted the registration.
293	//
294	// Start blocks until the initial registration completes (or fails). The
295	// heartbeat goroutine continues until Shutdown is called or ctx is canceled.
296	func (s *Spoke) Start(ctx context.Context) error {
297		if err := s.register(ctx); err != nil {
298			return err
299		}
300		// Persist current URL so the next start can detect a URL change.
301		_ = SaveSpokeState(s.statePath, &SpokeState{
302			NodeID:              s.cfg.NodeID,
303			IdentityFingerprint: s.identityFingerprint,
304			LastURL:             s.cfg.URL,
305		})
306		go s.heartbeatLoop(ctx)
307		return nil
308	}
309	
310	// Shutdown stops the heartbeat loop and sends a best-effort deregister.
311	// Safe to call multiple times. Always returns nil — deregister failures are
312	// logged but not surfaced (the hub may legitimately be down).
313	func (s *Spoke) Shutdown(ctx context.Context) error {
314		s.stopOnce.Do(func() { close(s.stopped) })
315	
316		// Best-effort deregister with a bounded timeout so a dead hub does not
317		// stall shutdown.
318		dctx, cancel := context.WithTimeout(ctx, s.cfg.DeregisterTimeout)
319		defer cancel()
320		if err := s.deregister(dctx); err != nil {
321			s.logf("federation: deregister best-effort failed: %v", err)
322		}
323		return nil
324	}
325	
326	// register POSTs /api/federation/register to the hub.
327	func (s *Spoke) register(ctx context.Context) error {
328		body := federationRegisterRequest{
329			NodeID:               s.cfg.NodeID,
330			IdentityFingerprint:  s.identityFingerprint,
331			Name:                 s.cfg.Name,
332			URL:                  s.cfg.URL,
333			DDxVersion:           s.cfg.DDxVersion,
334			SchemaVersion:        s.cfg.SchemaVersion,
335			GraphQLSchemaVersion: s.cfg.GraphQLSchemaVersion,
336			Capabilities:         append([]string(nil), s.cfg.Capabilities...),
337		}
338		resp, err := s.postJSON(ctx, "/api/federation/register", body)
339		if err != nil {
340			return err
341		}
342		defer func() { _ = resp.Body.Close() }()
343		if resp.StatusCode < 200 || resp.StatusCode >= 300 {
344			buf, _ := io.ReadAll(resp.Body)
345			return fmt.Errorf("federation register: hub returned %d: %s", resp.StatusCode, string(buf))
346		}
347		s.mu.Lock()
348		s.registered = true
349		s.registeredCount++
350		s.mu.Unlock()
351		return nil
352	}
353	
354	// deregister DELETEs /api/federation/spokes/<id>.
355	func (s *Spoke) deregister(ctx context.Context) error {
356		u, err := s.hubURL("/api/federation/spokes/" + url.PathEscape(s.cfg.NodeID))
357		if err != nil {
358			return err
359		}
360		req, err := http.NewRequestWithContext(ctx, http.MethodDelete, u, nil)
361		if err != nil {
362			return err
363		}
364		resp, err := s.cfg.HTTPClient.Do(req)
365		if err != nil {
366			return err
367		}
368		defer func() { _ = resp.Body.Close() }()
369		_, _ = io.Copy(io.Discard, resp.Body)
370		// 404 is fine — nothing to deregister.
371		if resp.StatusCode != http.StatusOK && resp.StatusCode != http.StatusNotFound {
372			return fmt.Errorf("federation deregister: hub returned %d", resp.StatusCode)
373		}
374		return nil
375	}
376	
377	// heartbeat POSTs /api/federation/heartbeat.
378	func (s *Spoke) heartbeat(ctx context.Context) error {
379		body := map[string]string{"node_id": s.cfg.NodeID}
380		resp, err := s.postJSON(ctx, "/api/federation/heartbeat", body)
381		if err != nil {
382			return err
383		}
384		defer func() { _ = resp.Body.Close() }()
385		_, _ = io.Copy(io.Discard, resp.Body)
386		if resp.StatusCode == http.StatusNotFound {
387			// Hub forgot us — re-register.
388			s.logf("federation: hub returned 404 on heartbeat; re-registering")
389			return s.register(ctx)
390		}
391		if resp.StatusCode < 200 || resp.StatusCode >= 300 {
392			return fmt.Errorf("federation heartbeat: hub returned %d", resp.StatusCode)
393		}
394		return nil
395	}
396	
397	// heartbeatLoop runs until ctx is canceled or Shutdown is called. Sleeps for
398	// HeartbeatInterval ± jitter between beats.
399	func (s *Spoke) heartbeatLoop(ctx context.Context) {
400		for {
401			d := s.nextHeartbeatDelay()
402			select {
403			case <-ctx.Done():
404				return
405			case <-s.stopped:
406				return
407			case <-time.After(d):
408			}
409			if err := s.heartbeat(ctx); err != nil {
410				s.mu.Lock()
411				s.hbErr = err
412				s.mu.Unlock()
413				s.logf("federation: heartbeat failed: %v", err)
414			} else {
415				s.mu.Lock()
416				s.hbErr = nil
417				s.heartbeatCount++
418				s.mu.Unlock()
419			}
420		}
421	}
422	
423	// NextHeartbeatDelay returns the next sleep duration the heartbeat loop will
424	// pick: HeartbeatInterval ± random jitter bounded by HeartbeatJitterFraction.
425	// Exposed so tests can verify jitter bounds without sleeping for 30s.
426	func (s *Spoke) NextHeartbeatDelay() time.Duration { return s.nextHeartbeatDelay() }
427	
428	// nextHeartbeatDelay returns interval ± random jitter in [0, jitter*interval].
429	func (s *Spoke) nextHeartbeatDelay() time.Duration {
430		base := s.cfg.HeartbeatInterval
431		jf := s.cfg.HeartbeatJitterFraction
432		if jf <= 0 {
433			return base
434		}
435		// Random offset in (-jf*base, +jf*base).
436		maxOffset := int64(float64(base) * jf)
437		if maxOffset <= 0 {
438			return base
439		}
440		n, err := rand.Int(rand.Reader, big.NewInt(2*maxOffset+1))
441		if err != nil {
442			return base
443		}
444		offset := n.Int64() - maxOffset
445		d := base + time.Duration(offset)
446		if d < 0 {
447			d = base
448		}
449		return d
450	}
451	
452	func (s *Spoke) hubURL(path string) (string, error) {
453		base := strings.TrimRight(s.cfg.HubURL, "/")
454		u, err := url.Parse(base + path)
455		if err != nil {
456			return "", err
457		}
458		return u.String(), nil
459	}
460	
461	func (s *Spoke) postJSON(ctx context.Context, path string, body any) (*http.Response, error) {
462		u, err := s.hubURL(path)
463		if err != nil {
464			return nil, err
465		}
466		buf, err := json.Marshal(body)
467		if err != nil {
468			return nil, err
469		}
470		req, err := http.NewRequestWithContext(ctx, http.MethodPost, u, bytes.NewReader(buf))
471		if err != nil {
472			return nil, err
473		}
474		req.Header.Set("Content-Type", "application/json")
475		return s.cfg.HTTPClient.Do(req)
476	}
477	
478	// federationRegisterRequest mirrors the hub-side request shape. Defined here
479	// to keep the federation package self-contained — the hub side
480	// (cli/internal/server/federation_hub.go) declares its own equivalent struct
481	// against the same wire contract.
482	type federationRegisterRequest struct {
483		NodeID               string   `json:"node_id"`
484		IdentityFingerprint  string   `json:"identity_fingerprint,omitempty"`
485		Name                 string   `json:"name"`
486		URL                  string   `json:"url"`
